// Givebutter webhook receiver for SignatureGate
// Recommended event: transaction.succeeded
// Expects webhook URL: /webhook/signaturegate/givebutter/transactions
//
// Optional auth: if GIVEBUTTER_SIGNING_SECRET is set in n8n env, require header 'Signature' to match.

const body = $json.body ?? $json;
const headers = ($json.headers ?? body.headers ?? {});

// Shared-secret header check (matches how Documenso hooks are handled: fail fast on bad payload)
const expected = ($env.GIVEBUTTER_SIGNING_SECRET || '').toString().trim();
if (expected) {
  const sig = (headers.signature || headers.Signature || headers.SIGNATURE || '').toString().trim();
  if (!sig) throw new Error('Missing Signature header for Givebutter webhook');
  if (sig !== expected) throw new Error('Invalid Signature header for Givebutter webhook');
}

// Normalize event name
const event = (body.event || body.type || body.name || '').toString();
if (!event) throw new Error(`Missing webhook event/type. Body: ${JSON.stringify(body)}`);

// Pull the transaction payload from common shapes
const data = body.data || body.payload || body.transaction || body;

// Try multiple email locations
const email = (
  data.email ||
  data.donor?.email ||
  data.supporter?.email ||
  data.payer?.email ||
  data.customer?.email ||
  ''
).toString().trim().toLowerCase();

// Givebutter transaction id / reference
const provider_reference = (
  data.id ||
  data.transaction_id ||
  data.transactionId ||
  data.reference ||
  data.reference_id ||
  ''
).toString();

if (!provider_reference) throw new Error(`Missing transaction id/reference. Body: ${JSON.stringify(body)}`);

// Amount handling (prefer cents fields if provided; otherwise treat as dollars and multiply by 100)
let amount_cents = null;
if (data.amount_cents != null) {
  amount_cents = Number(data.amount_cents);
} else if (data.amountCents != null) {
  amount_cents = Number(data.amountCents);
} else if (data.amount != null) {
  // some providers send cents in 'amount' - if this is Givebutter dollars, adjust as needed in future
  const v = Number(data.amount);
  amount_cents = Number.isFinite(v) ? Math.round(v * 100) : null;
} else if (data.donated != null) {
  const v = Number(data.donated);
  amount_cents = Number.isFinite(v) ? Math.round(v * 100) : null;
}

const currency = (data.currency || 'USD').toString().toUpperCase();

// Timestamp
const donated_at = data.transacted_at || data.transactedAt || data.created_at || data.createdAt || null;

// Notes (optional)
const notes = data.message || data.note || null;

const first_name = (data.first_name || '').toString();
const last_name = (data.last_name || '').toString();
const phone = (data.phone || '').toString();

return [{
  json: {
    event,
    email,
    provider: 'givebutter',   
    provider_reference,
    amount_cents,
    currency,
    donated_at,
    notes,
    first_name,
    last_name,
    phone,
    address: data.address || null,
    contact_id: data.contact_id || null,
    campaign_id: data.campaign_id || null,
    campaign_code: data.campaign_code || null,   
    raw: body
  }
}];
